// 1. Sadə union type
let id: string | number;
id = "A123";
console.log(id); // Çıxış: A123
id = 123;
console.log(id); // Çıxış: 123
// id = true; // Xəta: boolean string | number tipinə uyğun deyil

// 2. Funksiyada union type
function printValue(value: string | number): string {
  if (typeof value === "string") {
    return `String: ${value.toUpperCase()}`;
  }
  return `Number: ${value.toFixed(2)}`;
}
console.log(printValue("Hello")); // Çıxış: String: HELLO
console.log(printValue(42)); // Çıxış: Number: 42.00

// 3. Literal tiplərlə union type
type Status = "success" | "error" | "pending";
let status: Status = "success";
console.log(status); // Çıxış: success
// status = "failed"; // Xəta: failed Status tipinə uyğun deyil

// 4. Type narrowing ilə union type
function processResult(result: string | number | boolean): string {
  if (typeof result === "string") {
    return `String value: ${result}`;
  } else if (typeof result === "number") {
    return `Number value: ${result * 2}`;
  }
  return `Boolean value: ${result}`;
}
console.log(processResult("Test")); // Çıxış: String value: Test
console.log(processResult(10)); // Çıxış: Number value: 20
console.log(processResult(true)); // Çıxış: Boolean value: true

// 5. Obyektlərlə union type
interface Book {
  type: "book";
  title: string;
  pages: number;
}
interface Movie {
  type: "movie";
  title: string;
  duration: number;
}
type Media = Book | Movie;

function describeMedia(media: Media): string {
  if (media.type === "book") {
    return `${media.title} - ${media.pages} pages`;
  }
  return `${media.title} - ${media.duration} minutes`;
}
const book: Book = { type: "book", title: "TypeScript Guide", pages: 200 };
const movie: Movie = { type: "movie", title: "Inception", duration: 148 };
console.log(describeMedia(book)); // Çıxış: TypeScript Guide - 200 pages
console.log(describeMedia(movie)); // Çıxış: Inception - 148 minutes

// Sadə mağaza sistemi
type ProductId = string | number;
interface Product {
  id: ProductId;
  name: string;
  price: number;
}

function displayProduct(product: Product): string {
  const idDisplay = typeof product.id === "string" ? `ID: ${product.id}` : `Code: ${product.id}`;
  return `${idDisplay}, ${product.name}: $${product.price}`;
}

const laptop: Product = { id: "P001", name: "Laptop", price: 1200 };
const mouse: Product = { id: 123, name: "Mouse", price: 25 };
console.log(displayProduct(laptop)); // Çıxış: ID: P001, Laptop: $1200
console.log(displayProduct(mouse)); // Çıxış: Code: 123, Mouse: $25

// Status ilə union type
type OrderStatus = "pending" | "shipped" | "delivered";
function updateOrder(status: OrderStatus): string {
  return `Order status: ${status}`;
}
console.log(updateOrder("shipped")); // Çıxış: Order status: shipped

